"""Smoke tests for CLI script entrypoints."""from __future__ import annotationsimport astfrom pathlib import Pathimport pytestPROJECT_ROOT = Path(__file__).resolve().parents[3]EXCLUDED_SCRIPTS = {"run_ci_local.py"}SCRIPTS = sorted(    path    for path in (PROJECT_ROOT / "scripts").glob("*.py")    if path.name not in EXCLUDED_SCRIPTS)def _click_command_functions(tree: ast.Module) -> list[str]:    """Return function names decorated with @click.command."""    names: list[str] = []    for node in tree.body:        if not isinstance(node, ast.FunctionDef):            continue        for decorator in node.decorator_list:            if isinstance(decorator, ast.Call):                func = decorator.func                if (                    isinstance(func, ast.Attribute)                    and func.attr == "command"                    and isinstance(func.value, ast.Name)                    and func.value.id == "click"                ):                    names.append(node.name)            elif (                isinstance(decorator, ast.Attribute)                and decorator.attr == "command"                and isinstance(decorator.value, ast.Name)                and decorator.value.id == "click"            ):                names.append(node.name)    return namesdef _has_main_guard(tree: ast.Module) -> bool:    for node in tree.body:        if not isinstance(node, ast.If):            continue        test = node.test        if (            isinstance(test, ast.Compare)            and isinstance(test.left, ast.Name)            and test.left.id == "__name__"            and any(isinstance(op, ast.Eq) for op in test.ops)            and any(                isinstance(comp, ast.Constant) and comp.value == "__main__"                for comp in test.comparators            )        ):            return True    return False@pytest.mark.parametrize("script_path", SCRIPTS, ids=lambda p: p.name)def test_script_exposes_click_cli(script_path: Path) -> None:    """Each pipeline script should define a Click CLI entrypoint."""    tree = ast.parse(        script_path.read_text(encoding="utf-8"),        filename=str(script_path),    )    assert _click_command_functions(tree), (        f"{script_path.name} is missing an @click.command() entrypoint"    )    assert _has_main_guard(tree), (        f"{script_path.name} is missing an if __name__ == '__main__' guard"    )